async function main() {
  await mongoose.connect(MONGODB_URI);
  console.log('Connected to MongoDB');

  // Load ALL equipment for case-insensitive lookup
  const allEquipment = await Equipment.find({}).lean();
  const dbMapLower = new Map();
  for (const eq of allEquipment) {
    dbMapLower.set(eq.serialNumber.toLowerCase(), eq);
  }

  const skipCustomer = [];
  const alreadyDefective = [];
  const toUpdate = [];   // existing in DB -> mark defective
  const toInsert = [];   // not in DB -> create as defective

  for (const item of excelItems) {
    const eq = dbMapLower.get(item.sn);
    if (!eq) {
      toInsert.push(item);
      continue;
    }

    const isCustomer = (eq.location && eq.location.startsWith('user-')) ||
                       (eq.assignedToUser && eq.assignedToUser.length > 0) ||
                       eq.status === 'installed';
    if (isCustomer) {
      skipCustomer.push({ ...item, eq });
      continue;
    }

    if (eq.status === 'defective' || eq.location === 'defective') {
      alreadyDefective.push({ ...item, eq });
      continue;
    }

    toUpdate.push({ ...item, eq });
  }

  console.log('\n--- PLAN ---');
  console.log('Update existing -> defective: ' + toUpdate.length);
  console.log('Insert new as defective:      ' + toInsert.length);
  console.log('Skip (customer):              ' + skipCustomer.length);
  console.log('Skip (already defective):     ' + alreadyDefective.length);
  console.log('TOTAL to process:             ' + (toUpdate.length + toInsert.length));

  // ========== STEP 1: Update existing equipment to defective ==========
  console.log('\n========== UPDATING EXISTING EQUIPMENT ==========');
  let updateSuccess = 0;
  let updateFail = 0;

  for (const item of toUpdate) {
    try {
      const result = await Equipment.updateOne(
        { _id: item.eq._id },
        {
          $set: {
            status: 'defective',
            location: 'defective',
            assignedTo: null,
            assignedToUser: null,
            removedAt: new Date(),
          }
        }
      );
      if (result.modifiedCount === 1) {
        updateSuccess++;
      } else {
        console.log('  WARN: no modification for ' + item.eq.serialNumber);
        updateFail++;
      }
    } catch (err) {
      console.log('  ERROR updating ' + item.eq.serialNumber + ': ' + err.message);
      updateFail++;
    }
  }
  console.log('Updated: ' + updateSuccess + ' success, ' + updateFail + ' failed');

  // ========== STEP 2: Insert new equipment as defective ==========
  console.log('\n========== INSERTING NEW EQUIPMENT ==========');
  let insertSuccess = 0;
  let insertFail = 0;
  const insertErrors = [];

  // Batch insert in chunks of 100
  const chunkSize = 100;
  for (let i = 0; i < toInsert.length; i += chunkSize) {
    const chunk = toInsert.slice(i, i + chunkSize);
    const docs = chunk.map(item => ({
      serialNumber: item.sn,
      category: item.category,
      description: item.description,
      status: 'defective',
      location: 'defective',
      assignedTo: null,
      assignedToUser: null,
      removedAt: new Date(),
    }));

    try {
      const result = await Equipment.insertMany(docs, { ordered: false });
      insertSuccess += result.length;
    } catch (err) {
      // With ordered: false, some may succeed even if others fail
      if (err.insertedDocs) {
        insertSuccess += err.insertedDocs.length;
      }
      if (err.writeErrors) {
        for (const we of err.writeErrors) {
          insertFail++;
          insertErrors.push(we.errmsg || we.message);
        }
      } else {
        insertFail += chunk.length;
        insertErrors.push(err.message);
      }
    }
  }

  console.log('Inserted: ' + insertSuccess + ' success, ' + insertFail + ' failed');
  if (insertErrors.length > 0) {
    console.log('\nInsert errors (first 10):');
    for (const e of insertErrors.slice(0, 10)) {
      console.log('  ' + e);
    }
  }

  // ========== SUMMARY ==========
  console.log('\n========================================');
  console.log('           FINAL SUMMARY');
  console.log('========================================');
  console.log('Updated to defective:   ' + updateSuccess);
  console.log('Inserted as defective:  ' + insertSuccess);
  console.log('Skipped (customer):     ' + skipCustomer.length);
  console.log('Skipped (already def.): ' + alreadyDefective.length);
  console.log('Errors:                 ' + (updateFail + insertFail));
  console.log('TOTAL processed:        ' + (updateSuccess + insertSuccess));

  await mongoose.disconnect();
  console.log('\nDone.');
}

main().catch(err => { console.error('FATAL:', err); mongoose.disconnect(); process.exit(1); });
